/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Implements NotificationAdapter for the 'webhook' channel with:
 * - JSON payload formatting
 * - Configurable HTTP transport (defaults to in-memory for testing)
 * - URL validation
 *
 * Architecture constraint: all notification delivery goes through
 * adapters implementing NotificationAdapter, registered via
 * NotificationService.registerAdapter().
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface WebhookDelivery {
  url: string;
  payload: WebhookPayloadBody;
  sentAt: Date;
  notificationId: string;
}

export interface WebhookPayloadBody {
  id: string;
  type: string;
  channel: string;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  createdAt: string;
}

export interface WebhookConfig {
  /** Default webhook URL. Can be overridden per-notification via recipient field. */
  defaultUrl?: string;
  /** Optional transport function for sending webhooks. Defaults to in-memory storage. */
  transport?: WebhookTransport;
}

/**
 * Pluggable webhook transport. Return true for success, throw for failure.
 * In production, this would wrap fetch/axios/http client.
 */
export type WebhookTransport = (url: string, payload: WebhookPayloadBody) => Promise<boolean>;

export class WebhookAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'webhook';
  private logger = new Logger('WebhookAdapter');
  private deliveries: WebhookDelivery[] = [];
  private config: WebhookConfig;

  constructor(config?: WebhookConfig) {
    this.config = config ?? {};
  }

  /**
   * Send a webhook notification.
   * The recipient field is used as the webhook URL.
   * Never throws — returns a failed NotificationResult on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const url = this.resolveUrl(payload.recipient);

      if (!url) {
        this.logger.warn(`Invalid webhook URL: ${payload.recipient}`);
        return {
          success: false,
          channel: this.channel,
          error: `Invalid webhook URL: ${payload.recipient}`,
          deliveredAt: new Date(),
        };
      }

      const webhookBody = this.formatPayload(payload);

      if (this.config.transport) {
        await this.config.transport(url, webhookBody);
      }

      const delivery: WebhookDelivery = {
        url,
        payload: webhookBody,
        sentAt: new Date(),
        notificationId: payload.id,
      };

      this.deliveries.push(delivery);

      this.logger.info(`Webhook sent to ${url}: ${payload.subject}`);

      return {
        success: true,
        channel: this.channel,
        deliveredAt: new Date(),
      };
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to send webhook to ${payload.recipient}: ${errorMessage}`);
      return {
        success: false,
        channel: this.channel,
        error: `Webhook delivery failed: ${errorMessage}`,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Validate and resolve the webhook URL.
   * Uses the recipient as URL, falling back to defaultUrl if configured.
   * Returns null if no valid URL can be resolved.
   */
  resolveUrl(recipient: string): string | null {
    const url = recipient.trim() || this.config.defaultUrl;

    if (!url) {
      return null;
    }

    try {
      const parsed = new URL(url);
      if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
        return null;
      }
      return parsed.toString();
    } catch {
      return null;
    }
  }

  /**
   * Format a NotificationPayload into the JSON body sent to the webhook.
   */
  formatPayload(payload: NotificationPayload): WebhookPayloadBody {
    return {
      id: payload.id,
      type: payload.type,
      channel: payload.channel,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      metadata: payload.metadata,
      createdAt: payload.createdAt.toISOString(),
    };
  }

  /**
   * Get all sent webhook deliveries. Useful for testing.
   */
  getSentDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Clear delivery history.
   */
  clearDeliveries(): void {
    this.deliveries = [];
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'webhook',
    recipient: 'https://hooks.example.com/notify',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    createdAt: new Date('2024-01-01T00:00:00Z'),
    ...overrides,
  };
}

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;

  beforeEach(() => {
    adapter = new WebhookAdapter();
  });

  describe('channel', () => {
    it('should report webhook channel', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });

  describe('resolveUrl', () => {
    it('should accept valid HTTPS URLs', () => {
      expect(adapter.resolveUrl('https://hooks.example.com/notify')).toBe('https://hooks.example.com/notify');
    });

    it('should accept valid HTTP URLs', () => {
      expect(adapter.resolveUrl('http://localhost:3000/webhook')).toBe('http://localhost:3000/webhook');
    });

    it('should trim whitespace', () => {
      expect(adapter.resolveUrl('  https://hooks.example.com/notify  ')).toBe('https://hooks.example.com/notify');
    });

    it('should reject invalid URLs', () => {
      expect(adapter.resolveUrl('')).toBeNull();
      expect(adapter.resolveUrl('not-a-url')).toBeNull();
      expect(adapter.resolveUrl('ftp://files.example.com')).toBeNull();
    });

    it('should fall back to defaultUrl when recipient is empty', () => {
      const adapterWithDefault = new WebhookAdapter({
        defaultUrl: 'https://default.example.com/hook',
      });
      expect(adapterWithDefault.resolveUrl('')).toBe('https://default.example.com/hook');
    });

    it('should return null when no URL and no default', () => {
      expect(adapter.resolveUrl('')).toBeNull();
    });
  });

  describe('formatPayload', () => {
    it('should format notification payload as JSON body', () => {
      const payload = makePayload();
      const body = adapter.formatPayload(payload);

      expect(body.id).toBe('notif-0001');
      expect(body.type).toBe('order_confirmation');
      expect(body.channel).toBe('webhook');
      expect(body.recipient).toBe('https://hooks.example.com/notify');
      expect(body.subject).toBe('Order Confirmation: order-1');
      expect(body.body).toContain('Widget x2');
      expect(body.createdAt).toBe('2024-01-01T00:00:00.000Z');
    });

    it('should include metadata when present', () => {
      const payload = makePayload({ metadata: { orderId: 'order-1', total: 20 } });
      const body = adapter.formatPayload(payload);

      expect(body.metadata).toEqual({ orderId: 'order-1', total: 20 });
    });

    it('should handle missing metadata', () => {
      const payload = makePayload();
      const body = adapter.formatPayload(payload);

      expect(body.metadata).toBeUndefined();
    });
  });

  describe('send', () => {
    it('should send webhook successfully for valid URL', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.channel).toBe('webhook');
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should store delivery with correct fields', async () => {
      await adapter.send(makePayload());

      const deliveries = adapter.getSentDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe('https://hooks.example.com/notify');
      expect(deliveries[0]?.payload.id).toBe('notif-0001');
      expect(deliveries[0]?.payload.subject).toBe('Order Confirmation: order-1');
      expect(deliveries[0]?.notificationId).toBe('notif-0001');
      expect(deliveries[0]?.sentAt).toBeInstanceOf(Date);
    });

    it('should return failure for invalid URL', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-a-url' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
      expect(adapter.getSentDeliveries()).toHaveLength(0);
    });

    it('should return failure when transport throws', async () => {
      const failingAdapter = new WebhookAdapter({
        transport: async () => { throw new Error('Connection refused'); },
      });

      const result = await failingAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Connection refused');
    });

    it('should call custom transport when provided', async () => {
      const transport = vi.fn().mockResolvedValue(true);
      const customAdapter = new WebhookAdapter({ transport });

      await customAdapter.send(makePayload());

      expect(transport).toHaveBeenCalledOnce();
      const [url, body] = transport.mock.calls[0]!;
      expect(url).toBe('https://hooks.example.com/notify');
      expect(body.subject).toBe('Order Confirmation: order-1');
    });

    it('should use defaultUrl when recipient is empty', async () => {
      const transport = vi.fn().mockResolvedValue(true);
      const adapterWithDefault = new WebhookAdapter({
        defaultUrl: 'https://default.example.com/hook',
        transport,
      });

      await adapterWithDefault.send(makePayload({ recipient: '' }));

      expect(transport).toHaveBeenCalledOnce();
      const [url] = transport.mock.calls[0]!;
      expect(url).toBe('https://default.example.com/hook');
    });
  });

  describe('getSentDeliveries and clearDeliveries', () => {
    it('should return copies of sent deliveries', async () => {
      await adapter.send(makePayload());

      const deliveries1 = adapter.getSentDeliveries();
      const deliveries2 = adapter.getSentDeliveries();
      expect(deliveries1).not.toBe(deliveries2);
      expect(deliveries1).toEqual(deliveries2);
    });

    it('should clear delivery history', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentDeliveries()).toHaveLength(1);

      adapter.clearDeliveries();
      expect(adapter.getSentDeliveries()).toHaveLength(0);
    });
  });
});

